#include<cstdio>
#include<map>
#include<vector>
#include<cstring>
#include<cstdlib>
using namespace std;int W,H,EX,T[99][99],LK[99][99];map<int,map<int,int>>RM={{0,{}},{1,{{0,2},{1,2},{3,2}}},{2,{{1,3},{3,1}}},{3,{{0,2}}},{4,{{0,3},{1,2}}},{5,{{0,1},{1,2}}},{6,{{1,3},{3,1}}},{7,{{0,2},{1,2}}},{8,{{3,2},{1,2}}},{9,{{0,2},{3,2}}},{10,{{0,3}}},{11,{{0,1}}},{12,{{1,2}}},{13,{{3,2}}}};int RG[14][4]={{0},{1},{2,3},{3,2},{4,5},{5,4},{6,7,8,9},{7,8,9,6},{8,9,6,7},{9,6,7,8},{10,11,12,13},{11,12,13,10},{12,13,10,11},{13,10,11,12}};int RGS[]={1,1,2,2,2,2,4,4,4,4,4,4,4,4};int DX[]={0,1,0,-1},DY[]={-1,0,1,0},OPP[]={2,3,0,1};map<int,int>rot;int gt(int x,int y){int k=y*99+x;return rot.count(k)?rot[k]:T[y][x];}int gx(int t,int e){return RM[t].count(e)?RM[t][e]:-1;}struct Step{int x,y,t;};vector<Step>plan;bool dfs(int x,int y,int e){if(y>=H){return 1;}if(x<0||x>=W||y<0)return 0;int o=T[y][x],k=y*99+x;int n=RGS[o];for(int i=0;i<n;i++){int c=RG[o][i];if(LK[y][x]&&c!=gt(x,y))continue;int ex=gx(c,e);if(ex<0)continue;int nx=x+DX[ex],ny=y+DY[ex],ne=OPP[ex];int prev=rot.count(k)?rot[k]:-1;rot[k]=c;if(dfs(nx,ny,ne)){if(c!=T[y][x])plan.push_back({x,y,c});return 1;}if(prev>=0)rot[k]=prev;else rot.erase(k);}return 0;}vector<char*>Q;int main(){scanf("%d%d",&W,&H);for(int y=0;y<H;y++){for(int x=0;x<W;x++){scanf("%d",&T[y][x]);LK[y][x]=T[y][x]<0;T[y][x]=abs(T[y][x]);}}scanf("%d",&EX);for(;;){int xi,yi;char ent[9];scanf("%d%d%s",&yi,&xi,ent);int e=ent[0]=='T'?0:ent[0]=='R'?1:3;int R;scanf("%d",&R);for(int i=0;i<R;i++){int a,b;char d[9];scanf("%d%d%s",&a,&b,d);}if(Q.empty()){rot.clear();plan.clear();if(dfs(xi,yi,e)){for(auto&s:plan){int o=T[s.y][s.x],r=-1;for(int i=0;i<RGS[o];i++)if(RG[o][i]==s.t){r=i;break;}if(r<=0)continue;const char*d=r<=2?"RIGHT":"LEFT";int cnt=r<=2?r:4-r;for(int i=0;i<cnt;i++){char*buf=new char[20];sprintf(buf,"%d %d %s",s.x,s.y,d);Q.push_back(buf);}T[s.y][s.x]=s.t;}}}if(!Q.empty()){puts(Q[0]);Q.erase(Q.begin());}else puts("WAIT");}}